package se.medbo.examplatform.content.ai;
import jakarta.validation.Valid;import jakarta.validation.constraints.*;import java.util.List;import java.util.Map;import java.util.UUID;import org.springframework.http.HttpStatus;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/admin/ai") final class AiEditorialController {private final AiEditorialService service;AiEditorialController(AiEditorialService service){this.service=service;}
 record Create(@NotNull UUID sourceId,@NotNull UUID learningObjectiveId,@Min(1)@Max(20)int requestedCount,@NotBlank String language,@Size(max=1000)String editorialInstruction,@NotBlank String idempotencyKey){AiEditorialService.Create input(){return new AiEditorialService.Create(sourceId,learningObjectiveId,requestedCount,language,editorialInstruction,idempotencyKey);}}record Edit(@NotBlank@Size(max=500)String text,@PositiveOrZero long version){}record Decision(@Size(max=500)String reason,@PositiveOrZero long version){}record Accept(@PositiveOrZero long version){}
 @PostMapping("/knowledge-fact-jobs")@ResponseStatus(HttpStatus.ACCEPTED)Map<String,Object>create(@Valid@RequestBody Create r){return service.create(r.input());}@GetMapping("/knowledge-fact-jobs/{id}")Map<String,Object>job(@PathVariable UUID id){return service.job(id);}@PostMapping("/knowledge-fact-jobs/{id}/cancel")Map<String,Object>cancel(@PathVariable UUID id){return service.cancel(id);}@GetMapping("/knowledge-fact-jobs/{id}/proposals")List<Map<String,Object>>proposals(@PathVariable UUID id){return service.proposals(id);}@PatchMapping("/knowledge-fact-proposals/{id}")Map<String,Object>edit(@PathVariable UUID id,@Valid@RequestBody Edit r){return service.edit(id,new AiEditorialService.Edit(r.text(),r.version()));}@PostMapping("/knowledge-fact-proposals/{id}/reject")Map<String,Object>reject(@PathVariable UUID id,@Valid@RequestBody Decision r){return service.reject(id,new AiEditorialService.Decision(r.reason(),r.version()));}@PostMapping("/knowledge-fact-proposals/{id}/accept")Map<String,Object>accept(@PathVariable UUID id,@Valid@RequestBody Accept r){return service.accept(id,r.version());}@GetMapping("/knowledge-facts/{id}/provenance")Map<String,Object>provenance(@PathVariable UUID id){return service.provenance(id);}}
